import{_ as t,o as a,c as r,a5 as o}from"./chunks/framework.BsG5PWQ9.js";const u=JSON.parse('{"title":"Portal","description":"","frontmatter":{},"headers":[],"relativePath":"reference/components/portal.md","filePath":"reference/components/portal.md"}'),n={name:"reference/components/portal.md"};function i(s,e,l,c,h,d){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="portal" tabindex="-1">Portal <a class="header-anchor" href="#portal" aria-label="Permalink to &quot;Portal&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The <strong>Portal</strong> is the primary web interface for Platform Mesh. It is an Angular microfrontend shell built on the <a href="https://luigi-project.io" target="_blank" rel="noreferrer">Luigi</a> framework that composes IAM, Marketplace, and any custom extensions into a single, cohesive user experience.</p><p>The Portal acts as the <strong>orchestration layer</strong> for the entire Platform Mesh UI surface. Its responsibilities are:</p><ul><li><strong>Workspace navigation</strong> — lets users traverse the KCP workspace hierarchy (root → org → account → namespace) with context-aware navigation nodes that update as the selected workspace changes</li><li><strong>Org / account / namespace management</strong> — surfaces CRUD operations for the main Platform Mesh entities, delegating rendering to embedded microfrontends</li><li><strong>Kubeconfig download</strong> — generates and serves a ready-to-use kubeconfig scoped to the current workspace</li><li><strong>Home dashboard</strong> — shows a summary of the current workspace context (owner, path, service bindings)</li><li><strong>Terminal-as-a-Service</strong> — an in-browser shell powered by xterm.js and a ttyd-based WebSocket backend, available when the <code>terminal</code> feature toggle is enabled</li><li><strong>Microfrontend orchestration</strong> — loads and frames IAM UI, Marketplace UI, and any registered extension microfrontends inside Luigi iframes with shared authentication context</li><li><strong>Authentication shell</strong> — handles the OIDC / OAuth2 login flow via the Luigi OAuth2 plugin and forwards JWT tokens to all child microfrontends</li></ul><h2 id="runtime-role" tabindex="-1">Runtime role <a class="header-anchor" href="#runtime-role" aria-label="Permalink to &quot;Runtime role&quot;">​</a></h2><p>It lets users onboard organizations, navigate accounts, and navigate the KCP workspace hierarchy. All routing is owned by <strong>Luigi</strong>, not the Angular router — Luigi handles deep links, iframe lifecycle, and context propagation to child microfrontends. Navigation nodes (accounts, namespaces, IAM, Marketplace, Terminal) are built dynamically in TypeScript service classes that implement Luigi&#39;s node configuration interfaces.</p><p>Every navigation node is scoped to a <strong>KCP workspace path</strong> (e.g. <code>root:orgs:my-org:my-account</code>). The backend derives the active workspace path from the authenticated user&#39;s context and injects it into the Luigi <code>globalContext</code>, making it available to all child microfrontends without additional round-trips.</p><h2 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h2><ul><li><a href="https://github.com/platform-mesh/portal" target="_blank" rel="noreferrer">github.com/platform-mesh/portal</a></li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-138/reference/resources/content-configuration.html">ContentConfiguration</a></li><li><a href="/pr-preview/pr-138/tutorials/explore-example-msp.html">Explore the example MSP</a></li></ul>',12)])])}const g=t(n,[["render",i]]);export{u as __pageData,g as default};
